      <div class="row">
        <div class="col-md-12 padding-t_8">
          <div class="theme-primary partition-full">
            <span class="p-name text-white">{{ $t('Manage') }} {{ $t('ContextMenu') }}</span>
          </div>
        </div>
      </div>
    </section>
    <section class="main-content" >

      <div class="border p-3 form-minheight">
        <div class="row">
          <ul class="dashbord-widget px-3 d-flex align-items-center">
            <li class="one_wid d-flex align-items-center">
              <a @click="LoadData" class="bgcompanyadmin d-flex align-items-center w-100">
                <h3>{{$t('CompanyAdmin')}}</h3>
                <i class="w-100">
                  <img src="https://talygenv.github.io/Vue-UI-Content/images/admin.png" />
                </i>
              </a>
            </li>

            <li class="two_wid d-flex align-items-center">
              <a @click="LoadData" class="projectmanager d-flex align-items-center w-100">
                <h3>{{$t('PROJECT_MANAGER')}}</h3>
                <i class="w-100">
                  <img src="https://talygenv.github.io/Vue-UI-Content/images/manager.png" />
                </i>
              </a>
            </li>

            <li class="three_wid d-flex align-items-center">
              <a @click="LoadData" class="normaluser d-flex align-items-center w-100">
                <h3>{{$t('NormalUser')}}</h3>
                <i class="w-100">
                  <img src="https://talygenv.github.io/Vue-UI-Content/images/user.png" />
                </i>
              </a>
