</template>
<script>
export default {
  data() {
    return {
        UserTypeId:0
    };
  },
  created(){
    const type = this.GetUserInfo?.UserType;
    this.UserTypeId = type === "CA" ? 1 : type === "PM" ? 2 : type === "CL" ? 4 : 3;
  },
  methods: {
    LoadData() {
      this.$router.push({ name: 'ViewContextMenuById', params: { id: this.UserTypeId} });
    }
  },
};
</script>